wolfram_code:
Module[{nBridges = 12, nE8 = 3, dim = 24, nFaces, bpf, faces, crossE8, allCovered, noDup, nGenOk, h11Ok},
  nFaces = 4;
  bpf = nBridges / nFaces;
  (* Face i contains bridges {i, i+4, i+8} -- one from each E8 copy *)
  faces = Table[Table[f + 4*e, {e, 0, nE8 - 1}], {f, 0, nFaces - 1}];
  (* Check 1: cross-E8 -- each face has one bridge from each E8 block *)
  crossE8 = AllTrue[faces, (Sort[Quotient[#, 4]] == {0, 1, 2}) &];
  (* Check 2: all 12 bridges covered *)
  allCovered = (Sort[Flatten[faces]] == Range[0, 11]);
  (* Check 3: no duplicate bridges *)
  noDup = (Length[Flatten[faces]] == Length[Union[Flatten[faces]]]);
  (* Check 4: n_gen consistency (3 = dim/8) *)
  nGenOk = (bpf == dim/8);
  (* Check 5: h11 consistency (4 faces) *)
  h11Ok = (nFaces == Length[faces]);
  {nFaces, bpf, crossE8, allCovered, noDup, nGenOk, h11Ok,
   If[crossE8 && allCovered && noDup && nGenOk && h11Ok, "DERIVED", "FAILED"]}
]
